// @vitest-environment node
/**
 * SPEC-023: optimización de latencia del asistente — prefijo fijo cacheado
 * (system en bloques con cache_control ephemeral), estabilidad byte a byte
 * entre llamadas, mensaje de usuario reducido a la parte variable, salida
 * acotada por schema (maxLength 200/140) y max_tokens 512.
 * Generated by QA Dev agent.
 *
 * Arnés de SPEC-016 (SDK/Deepgram mockeados, transcripción real, fake Date).
 * El formato de la sección de conversación ('[mic sN] texto' / '[mic] texto')
 * lo fijan las suites de SPEC-016/022 — aquí se aserta que la ventana queda
 * FUERA del prefijo cacheado y las secciones variables conservan su forma.
 */
import { mkdtempSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import type { WebContents } from 'electron'
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import { MIN_INTERVAL_MS, startAssistant, stopAssistant } from '../../../src/main/assistantService'
import * as repository from '../../../src/main/db/repository'
import { initStore } from '../../../src/main/db/store'
import type { DeepgramCallbacks } from '../../../src/main/deepgramService'
import { resetTranscription, startTranscription } from '../../../src/main/transcriptionService'

const harness = vi.hoisted(() => {
  class APIError extends Error {}
  class AuthenticationError extends APIError {}
  class RateLimitError extends APIError {}
  class APIConnectionError extends APIError {}
  return {
    create: vi.fn(),
    dgInstances: [] as unknown[],
    errors: { APIError, AuthenticationError, RateLimitError, APIConnectionError }
  }
})

vi.mock('@anthropic-ai/sdk', () => {
  class MockAnthropic {
    static APIError = harness.errors.APIError
    static AuthenticationError = harness.errors.AuthenticationError
    static RateLimitError = harness.errors.RateLimitError
    static APIConnectionError = harness.errors.APIConnectionError
    readonly messages = { create: harness.create }
  }
  return { default: MockAnthropic }
})

vi.mock('../../../src/main/deepgramService', () => ({
  DeepgramConnection: class {
    apiKey: string
    callbacks: DeepgramCallbacks
    opened = false
    isOpen = false
    sendAudio = vi.fn(() => true)
    sendKeepAlive = vi.fn()
    closeStream = vi.fn()
    terminate = vi.fn()

    constructor(apiKey: string, callbacks: DeepgramCallbacks) {
      this.apiKey = apiKey
      this.callbacks = callbacks
      harness.dgInstances.push(this)
    }
  },
  classifyConnectionFailure: vi.fn(() => Promise.resolve('other' as const))
}))

vi.mock('electron', () => ({
  app: {
    getPath: (): string => {
      throw new Error('app.getPath no debe usarse en tests: initStore recibe baseDir inyectado')
    }
  },
  safeStorage: {
    isEncryptionAvailable: (): boolean => true,
    encryptString: (plain: string): Buffer => Buffer.from(plain, 'utf8'),
    decryptString: (blob: Buffer): string => blob.toString('utf8')
  }
}))

interface FakeConnection {
  callbacks: DeepgramCallbacks
  opened: boolean
  isOpen: boolean
}

/** Bloque del system en formato de bloques (forma enviada al SDK). */
interface SystemBlock {
  type: string
  text: string
  cache_control?: { type: string }
}

/** Parámetros relevantes de una llamada create del asistente. */
interface CreateParams {
  max_tokens: number
  system: SystemBlock[]
  messages: Array<{ role: string; content: string }>
  output_config: {
    format: {
      type: string
      schema: {
        properties: {
          suggestedQuestion: { maxLength?: number }
          reason: { maxLength?: number }
        }
      }
    }
  }
}

function createCall(index: number): CreateParams {
  return harness.create.mock.calls[index][0] as CreateParams
}

function sdkResponse(payload: Record<string, unknown>): unknown {
  return {
    stop_reason: 'end_turn',
    content: [
      { type: 'thinking', thinking: 'razonamiento' },
      { type: 'text', text: JSON.stringify(payload) }
    ]
  }
}

function analysisPayload(overrides: Record<string, unknown> = {}): Record<string, unknown> {
  return {
    action: 'continue',
    suggestedQuestion: '¿Cuándo fue la última vez que pasó?',
    reason: 'Ya hay material concreto para avanzar',
    alarms: [],
    objectivesMet: [],
    ...overrides
  }
}

function createSender(): { sender: WebContents; send: ReturnType<typeof vi.fn> } {
  const send = vi.fn()
  const senderLike = {
    isDestroyed: (): boolean => false,
    send
  }
  return { sender: senderLike as unknown as WebContents, send }
}

const BASE_TIME_MS = 1_000_000_000

let connection: FakeConnection
let lineCounter = 0

function feedFinal(text?: string): void {
  lineCounter += 1
  connection.callbacks.onResult({
    channelIndex: lineCounter % 2,
    transcript: text ?? `Línea de conversación ${lineCounter}`,
    isFinal: true,
    startSeconds: lineCounter,
    durationSeconds: 1,
    speaker: 0
  })
}

/**
 * Sesión sobre una captura CON objetivos y guión (el prefijo cacheable
 * completo); `withContext: false` arranca sin objetivos ni guión.
 */
function startSession(options: { withContext?: boolean } = {}): void {
  const { withContext = true } = options
  const discovery = repository.createDiscovery({ name: 'Vertical Sanidad' })
  const interview = repository.createInterview({
    discoveryId: discovery.id,
    title: 'Captura latencia'
  })
  if (withContext) {
    repository.updateInterview(interview.id, {
      objectives: ['Objetivo cero', 'Objetivo uno', 'Objetivo dos'],
      scriptMarkdown: '# Guión adaptado\nPregunta clave para la llamada'
    })
  }

  const transcriptionSender = createSender()
  startTranscription(transcriptionSender.sender)
  connection = harness.dgInstances[0] as FakeConnection
  connection.opened = true
  connection.isOpen = true
  connection.callbacks.onOpen()

  startAssistant(createSender().sender, interview.id)
}

async function waitForCreateCalls(count: number): Promise<void> {
  await vi.waitFor(() => expect(harness.create).toHaveBeenCalledTimes(count))
}

/** Dos análisis consecutivos de la misma sesión (el 1º cubre el objetivo 0). */
async function runTwoAnalyses(): Promise<void> {
  harness.create.mockResolvedValueOnce(sdkResponse(analysisPayload({ objectivesMet: [0] })))
  feedFinal()
  feedFinal()
  feedFinal()
  await waitForCreateCalls(1)

  harness.create.mockResolvedValueOnce(sdkResponse(analysisPayload()))
  vi.setSystemTime(BASE_TIME_MS + MIN_INTERVAL_MS + 1000)
  feedFinal()
  feedFinal()
  feedFinal()
  await waitForCreateCalls(2)
}

beforeEach(() => {
  vi.clearAllMocks()
  harness.dgInstances.length = 0
  lineCounter = 0
  vi.useFakeTimers({ toFake: ['Date'] })
  vi.setSystemTime(BASE_TIME_MS)
  initStore(mkdtempSync(join(tmpdir(), 'maurya-latency-')))
  process.env['ANTHROPIC_API_KEY'] = 'sk-ant-test'
  process.env['DEEPGRAM_API_KEY'] = 'dg-test'
})

afterEach(() => {
  stopAssistant()
  resetTranscription()
  vi.useRealTimers()
  delete process.env['ANTHROPIC_API_KEY']
  delete process.env['DEEPGRAM_API_KEY']
})

describe('assistantService (latencia SPEC-023)', () => {
  // SPEC-023 · AC-01
  it('sends the fixed prefix (instructions + script/objectives) as system blocks with ephemeral cache_control only on the last block, keeping the transcript window out', async () => {
    harness.create.mockResolvedValue(sdkResponse(analysisPayload()))
    startSession()
    feedFinal('primera frase de la conversación')
    feedFinal()
    feedFinal()
    await waitForCreateCalls(1)

    const params = createCall(0)
    // system en formato de bloques: instrucciones + contexto fijo
    expect(Array.isArray(params.system)).toBe(true)
    expect(params.system).toHaveLength(2)
    expect(params.system[0].type).toBe('text')
    // cache_control ephemeral SOLO en el último bloque
    expect(params.system[0].cache_control).toBeUndefined()
    expect(params.system[1].cache_control).toEqual({ type: 'ephemeral' })
    // El bloque fijo lleva los objetivos numerados SIN estado y el guión
    expect(params.system[1].text).toContain('## Objetivos de la entrevista')
    expect(params.system[1].text).toContain('0. Objetivo cero')
    expect(params.system[1].text).not.toMatch(/\[(cubierto|pendiente)\]/)
    expect(params.system[1].text).toContain('## Guión de la entrevista')
    expect(params.system[1].text).toContain('Pregunta clave para la llamada')
    // Solo la ventana de transcripción queda fuera del prefijo cacheado
    const systemText = params.system.map((block) => block.text).join('\n')
    expect(systemText).not.toContain('primera frase de la conversación')
    expect(params.messages[0].content).toContain('primera frase de la conversación')
  })

  // SPEC-023 · AC-02
  it('keeps the cached prefix byte-identical across two analyses while only the variable user message changes', async () => {
    startSession()
    await runTwoAnalyses()

    const first = createCall(0)
    const second = createCall(1)
    // Prefijo byte a byte idéntico (condición necesaria del acierto de caché),
    // aunque entre llamadas cambiaron objectivesMet y la conversación
    expect(JSON.stringify(second.system)).toBe(JSON.stringify(first.system))

    // El estado dinámico viaja compacto en el user: índices cubiertos
    expect(first.messages[0].content).toContain('## Objetivos ya cubiertos (índices)\nninguno')
    expect(second.messages[0].content).toContain('## Objetivos ya cubiertos (índices)\n0')
    // El user NO lleva ni marcadores de estado ni el guión (viven en el prefijo)
    expect(second.messages[0].content).not.toMatch(/\[(cubierto|pendiente)\]/)
    expect(second.messages[0].content).not.toContain('## Guión de la entrevista')
    expect(second.messages[0].content).not.toContain('Objetivo cero')
    // Las secciones variables conservan su forma histórica
    expect(second.messages[0].content).toContain(
      '## Conversación reciente (mic = entrevistador, system = interlocutor)'
    )
    expect(second.messages[0].content).toContain('## Tu sugerencia anterior (no la repitas)')
    expect(second.messages[0].content).toContain('¿Cuándo fue la última vez que pasó?')
    expect(second.messages[0].content).toContain('## Tarea')
  })

  // SPEC-023 · AC-01/AC-02 (refuerzo: sin objetivos ni guión el prefijo es un
  // único bloque cacheado y la sección de índices se omite)
  it('omits the covered-objectives section and caches the single instructions block when the interview has no objectives nor script', async () => {
    harness.create.mockResolvedValue(sdkResponse(analysisPayload()))
    startSession({ withContext: false })
    feedFinal()
    feedFinal()
    feedFinal()
    await waitForCreateCalls(1)

    const params = createCall(0)
    expect(params.system).toHaveLength(1)
    expect(params.system[0].cache_control).toEqual({ type: 'ephemeral' })
    expect(params.messages[0].content).not.toContain('## Objetivos ya cubiertos')
  })

  // SPEC-023 · AC-04
  it('declares maxLength 200/140 in the structured output schema sent and instructs the same brevity limits in the prompt', async () => {
    harness.create.mockResolvedValue(sdkResponse(analysisPayload()))
    startSession()
    feedFinal()
    feedFinal()
    feedFinal()
    await waitForCreateCalls(1)

    const params = createCall(0)
    // Los topes viven en el propio schema del structured output…
    expect(params.output_config.format.schema.properties.suggestedQuestion.maxLength).toBe(200)
    expect(params.output_config.format.schema.properties.reason.maxLength).toBe(140)
    // …y el prompt instruye la brevedad con LOS MISMOS números (una frase corta)
    expect(params.system[0].text).toContain('máximo 200 caracteres')
    expect(params.system[0].text).toContain('UNA sola frase corta (máximo 140 caracteres)')
  })

  // SPEC-023 · AC-06
  it('sends max_tokens 512 for the assistant analysis calls', async () => {
    harness.create.mockResolvedValue(sdkResponse(analysisPayload()))
    startSession()
    feedFinal()
    feedFinal()
    feedFinal()
    await waitForCreateCalls(1)

    expect(createCall(0).max_tokens).toBe(512)
  })
})
